```sql
CREATE TABLE TableA (
  EmployeeName VARCHAR(50),
  DepartmentID INT
);

CREATE TABLE TableB (
  DepartmentID INT,
  DepartmentName VARCHAR(50)
);

INSERT INTO TableA (EmployeeName, DepartmentID)
VALUES ('John', 123), ('Peter', 345);

INSERT INTO TableB (DepartmentID, DepartmentName)
VALUES (123, 'Human Resource'), (678, 'Accounting');
```

These queries will create the tables `TableA` and `TableB`, and then insert the given data into them.

